import React from 'react';
import { View, Text, Button } from 'react-native';

class App extends React.Component {
  state = {
    userProfile: null,
    isAuthenticated: false,
  };

  async authenticate(username, password) {
    try {
      const response = await fetch('https://api.example.com/auth', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ username, password }),
      });
      if (response.ok) {
        const data = await response.json();
        this.setState({ isAuthenticated: true, userProfile: data.user });
      } else {
        throw new Error('Authentication failed');
      }
    } catch (error) {
      console.error(error);
    }
  }

  async fetchUserProfile() {
    try {
      if (!this.state.isAuthenticated) {
        throw new Error('User is not authenticated');
      }
      const response = await fetch('https://api.example.com/user', {
        headers: {
          'Authorization': `Bearer ${this.state.userProfile.token}`,
        },
      });
      if (response.ok) {
        const data = await response.json();
        this.setState({ userProfile: { ...this.state.userProfile, ...data } });
      } else {
        throw new Error('Failed to fetch user profile');
      }
    } catch (error) {
      console.error(error);
    }
  }

  async updateData(data) {
    try {
      if (!this.state.isAuthenticated) {
        throw new Error('User is not authenticated');
      }
      const response = await fetch('https://api.example.com/update', {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${this.state.userProfile.token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(data),
      });
      if (response.ok) {
        const updatedData = await response.json();
        this.setState({ userProfile: { ...this.state.userProfile, ...updatedData } });
      } else {
        throw new Error('Failed to update data');
      }
    } catch (error) {
      console.error(error);
    }
  }

  render() {
    return (
      <View>
        <Text>{this.state.isAuthenticated ? 'Authenticated' : 'Not Authenticated'}</Text>
        {this.state.isAuthenticated && (
          <>
            <Button title="Fetch User Profile" onPress={this.fetchUserProfile} />
            <Button title="Update Data" onPress={() => this.updateData({ key: 'value' })} />
          </>
        )}
      </View>
    );
  }
}

export default App;